class LineReport { public string Name; public int Qty, Good; public LineReport(string n, int q, int g) { Name=n; Qty=q; Good=g; } }
var lines = new LineReport[] {
    new LineReport("A线", 10000, 9850),
    new LineReport("B线", 8000, 7920),
    new LineReport("C线", 12000, 11800)
};
int tQty=0, tGood=0, maxQty=0; string best="";
foreach (var l in lines) {
    tQty+=l.Qty; tGood+=l.Good;
    double r = l.Good*100.0/l.Qty;
    Print($"{l.Name}: {l.Qty}件 良品率{r:F1}%");
    if (l.Qty>maxQty) { maxQty=l.Qty; best=l.Name; }
}
Print($"总产量:{tQty} 平均良品率:{tGood*100.0/tQty:F1}% 最高:{best}");
Print("===== 月度报表 =====");
